const body = $input.first().json.body;
const messageType = body.message?.type || 'unknown';
const call = body.message?.call || {};
const customerPhone = call.customer?.number || null;

return [{
  json: {
    messageType,
    customerPhone,
    callId: call.id,
    functionCall: body.message?.functionCall || null,
    endOfCallReport: body.message?.endOfCallReport || null,
    statusUpdate: body.message?.status || null
  }
}];

// Handle log_confirmation_status function call from the reminder agent
const funcCall = $input.first().json.functionCall;
const params = funcCall?.parameters || {};
const status = params.status || 'unknown';
const notes = params.notes || '';

// If customer wants to cancel, flag for human follow-up
const needsFollowUp = ['wants_cancel', 'wants_reschedule'].includes(status);

return [{
  json: {
    result: JSON.stringify({
      acknowledged: true,
      status: status,
      message: status === 'confirmed' 
        ? 'Customer confirmed. Tell them you are excited to see them!'
        : status === 'wants_cancel'
        ? 'Noted. Let the customer know a team member will reach out shortly to process the cancellation.'
        : status === 'wants_reschedule'
        ? 'Noted. Let the customer know a team member will call them back to find a new time.'
        : 'Noted. Thank the customer for their time.'
    }),
    needs_follow_up: needsFollowUp,
    confirmation_status: status,
    confirmation_notes: notes
  }
}];

// Process end-of-call report from reminder call
const input = $input.first().json;
const report = input.endOfCallReport || {};
const phone = input.customerPhone;

return [{
  json: {
    customer_phone: phone,
    call_id: input.callId,
    transcript: report.transcript || '',
    summary: report.summary || '',
    duration_seconds: report.durationSeconds || 0,
    ended_reason: report.endedReason || 'unknown',
    cost: report.cost || 0
  }
}];

// Check if customer wanted to cancel/reschedule during reminder call
// If so, flag for salon owner via SMS alert
const transcript = $('Code: Parse End-of-Call Report').first().json.transcript.toLowerCase();
const customerName = $('Supabase: Lookup Customer').first().json[0]?.name || 'Customer';
const phone = $('Code: Parse End-of-Call Report').first().json.customer_phone;

const wantsCancel = transcript.includes('cancel') || transcript.includes('can\'t make it');
const wantsReschedule = transcript.includes('reschedule') || transcript.includes('different time') || transcript.includes('change');
const noAnswer = $('Code: Parse End-of-Call Report').first().json.ended_reason === 'voicemail';

return [{
  json: {
    needs_followup: wantsCancel || wantsReschedule,
    followup_reason: wantsCancel ? 'wants_cancel' : wantsReschedule ? 'wants_reschedule' : noAnswer ? 'no_answer' : 'confirmed',
    customer_name: customerName,
    customer_phone: phone,
    alert_message: wantsCancel 
      ? `⚠️ ALERT: ${customerName} (${phone}) wants to CANCEL their appointment today. Please follow up.`
      : wantsReschedule
      ? `📅 HEADS UP: ${customerName} (${phone}) wants to RESCHEDULE their appointment today. Please follow up.`
      : noAnswer
      ? `📞 ${customerName} (${phone}) didn't answer their reminder call. Their appointment is in ~1 hour.`
      : null
  }
}];
